{
  "experiment_plan": {
    "what_to_compare": "淮河境界の直近にある北側都市と南側都市を比較し、running variable（淮河からの緯度距離）が0をまたぐ前後での不連続を評価する。主要比較は、(1) TSP濃度、(2) 平均寿命、(3) 心肺疾患死亡率、(4) 交絡候補の共変量（医療アクセス、産業構成、所得、気候指標）で行う。H2とH3は独立に判定するため、H2は共変量バランスと媒介調整後の寿命不連続、H3は推定仕様（3次多項式、局所線形、複数バンド幅）間の効果量差のみで判定する。",
    "what_to_measure": "都市レベルで、境界からの距離、TSP濃度、平均寿命、心肺疾患死亡率、年齢層別死亡率、医療資源指標、産業構成、所得、気温・湿度などを測定する。加えて、仕様別のRDD推定値、標準誤差、信頼区間、バンド幅感度、次数感度を記録する。",
    "procedure": "1) 淮河境界から一定距離内の都市サンプルを抽出する。2) まず第一段階として、境界をまたぐTSPの不連続をRDDで推定する。3) 次に平均寿命と心肺疾患死亡率について同じRDDを実施する。4) 共変量の連続性検定を行い、境界での不連続がないか確認する。5) 仕様感度分析として、3次多項式RDD、局所線形RDD、複数バンド幅、データ駆動型バンド幅を比較する。6) 媒介分析としてTSPを入れたモデルと入れないモデルを比較する。7) 年齢層別・アウトカム別の異質性を確認する。8) 各仮説について事前に定めた判定規則に従い、accept/reject/holdを決定する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "淮河境界の近傍では、境界をまたいで都市の潜在的な反実仮想アウトカムが連続であり、境界そのもの以外の要因が急変しないこと。",
        "if_violated": "RDDによる因果解釈が成立せず、観測された不連続を政策効果と区別できない。"
      },
      {
        "id": "IA2",
        "description": "境界近傍で都市が戦略的に位置選択されておらず、running variableの操作や選別がないこと。",
        "if_violated": "境界付近の比較が非ランダムになり、推定された不連続が選別バイアスを含む。"
      },
      {
        "id": "IA3",
        "description": "TSP濃度の境界不連続が政策によって生じ、他の同時的ショックではないこと。",
        "if_violated": "第一段階が政策効果を表さず、媒介経路の解釈が崩れる。"
      },
      {
        "id": "IA4",
        "description": "境界近傍で共変量が連続であり、医療アクセス・所得・産業構成・気候などの観測可能な交絡が急変しないこと。",
        "if_violated": "H2の識別が困難になり、寿命差を他要因に帰属できなくなる。"
      },
      {
        "id": "IA5",
        "description": "仕様感度分析で用いる局所線形推定やバンド幅選択が、極端な外れ値や過度の平滑化に支配されないこと。",
        "if_violated": "H3の判定が仕様依存性ではなく推定不安定性を反映する可能性がある。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "境界近傍で北側のTSPが南側より有意に高く、かつ平均寿命が北側で有意に低い不連続が、主要仕様（3次多項式RDD、局所線形RDD、複数バンド幅）で同方向かつ概ね一貫して観察される。",
        "reject_if": "TSPに不連続がなく、かつ平均寿命にも一貫した不連続が観察されない、または方向が不安定である。",
        "hold_if": "TSPの不連続は確認されるが、平均寿命の不連続が仕様間で不安定、または統計的に不明瞭である。"
      },
      {
        "id": "H2",
        "accept_if": "共変量の境界不連続が検出されず、TSPを調整しても平均寿命の不連続が残り、かつその残差がTSPの不連続と整合的である。",
        "reject_if": "医療アクセス、所得、産業構成、気候などの共変量に境界不連続があり、それらを調整すると平均寿命の不連続が大きく減衰または消失する。",
        "hold_if": "共変量の一部に小さな不連続があるが、調整後の寿命不連続の解釈が明確に決まらない。"
      },
      {
        "id": "H3",
        "accept_if": "3次多項式RDDの推定値が局所線形RDDや狭いバンド幅推定よりも明確に大きく、仕様変更で効果量が有意に縮小する。",
        "reject_if": "3次多項式、局所線形、異なるバンド幅のいずれでも効果量がほぼ同程度で、推定値が大きく変わらない。",
        "hold_if": "仕様間で効果量に差はあるが、縮小が一貫的でも十分大きくもなく、判定が不確実である。"
      },
      {
        "id": "H4",
        "accept_if": "平均寿命よりも心肺疾患死亡率の不連続が大きく、特に高齢層でより強い不連続が観察される。",
        "reject_if": "心肺疾患死亡率に不連続がなく、平均寿命のみが変化する、または年齢層別に高齢層での増悪が見られない。",
        "hold_if": "心肺疾患死亡率の不連続はあるが、平均寿命との差や年齢層別パターンが明確でない。"
      }
    ],
    "analysis_forks": [
      "主要仕様として3次多項式RDDを用いる分岐と、局所線形RDDを用いる分岐を別々に推定する。",
      "バンド幅を狭い・中程度・データ駆動型に分けて感度分析する分岐を設ける。",
      "共変量調整あり/なしでH2を判定する分岐を設ける。",
      "TSPを媒介変数として含めるモデルと含めないモデルを比較する分岐を設ける。",
      "アウトカムを平均寿命と心肺疾患死亡率に分け、さらに年齢層別に分解する分岐を設ける。",
      "H2とH3はindependentなので、H2の判定は共変量連続性と媒介調整後の寿命不連続のみで行い、H3の判定は仕様間の効果量差のみで行う。"
    ]
  }
}
